class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def append(self, data):
        new_node = Node(data)
        if self.head is None:
            self.head = new_node
            return
        last_node = self.head
        while last_node.next:
            last_node = last_node.next
        last_node.next = new_node

    def search_sublist(self, sublist):
        if sublist.head is None:
            return True

        if self.head is None:
            return False

        current_main = self.head

        while current_main:
            pointer1 = current_main
            pointer2 = sublist.head

            while pointer1 and pointer2:
                if pointer1.data == pointer2.data:
                    pointer1 = pointer1.next
                    pointer2 = pointer2.next
                else:
                    break

            if pointer2 is None:
                return True

            current_main = current_main.next

        return False
